using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for complex/decimal-precise cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalTestData))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalTestData =>
    [
        (100.00m, 1, 0.0m, 100.00m),
        (100.00m, 1, 0.07m, 107.00m),
        (19.99m, 4, 0.065m, 85.1574m),
        (0.01m, 100, 1.0m, 2.00m),
    ];

    // --- CalculateTotal: invalid inputs throw ---

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // --- ApplyDiscount: DataRow for inline values ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off 100")]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "50% off 49.99")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off 200")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for decimal precision ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountTestData))]
    public void ApplyDiscount_WithDynamicData_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountTestData =>
    [
        (1000.00m, 15.0m, 850.00m),
        (79.99m, 33.33m, 53.327667m),
        (0.00m, 50.0m, 0.00m),
    ];

    // --- ApplyDiscount: invalid inputs throw ---

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount")]
    [DataRow(100.00, 100.01, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double price, double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent));
    }
}

